import React, { useEffect, useRef, useState } from "react";
import DataTable from "react-data-table-component";
import { customStyles } from "../../utils/tableCustomStyles";
import { tableUserViewQueryConstant } from "./tableUserViewQueryConstant";
import { deleteUserViewQuery, getAllUserViewQuery } from "src/components/services/UserViewQuery";
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { CSVLink } from "react-csv";
import Select from 'react-select';
import { businessStatusOption, deleteModalSwal, epochTogmt } from "src/utils/Common";
import authService from "src/auth/auth.service";

const MySwal = withReactContent(alertPopUp);

const UserViewQueryList = () => {
    const csvLink = useRef()
    const [rowData, setRowData] = useState([]);
    const [perPage, setPerPage] = useState(10);
    const [selectData, setSelectData] = useState({ statusData: { value: 'NEW', label: 'NEW' }, });
    const [loading, setLoading] = useState(false);
    const [totalRows, setTotalRows] = useState(0);
    const [exportCsvData, setExportCsvData] = useState([]);
    const [fileName, setFileName] = useState("");

    const userViewQueryListHeader = [
        { label: "Create Date", key: "createTime" },
        { label: "First Name", key: "firstName" },
        { label: "Last Name", key: "lastName" },
        { label: "Country code", key: "countryCode" },
        { label: "Phone No", key: "phoneNumber" },
        { label: "Email", key: "email" },
        { label: "Company Name", key: "companyName" },
        { label: "Website", key: "website" },
        { label: "City", key: "city" },
        { label: "State", key: "state" },
        { label: "Country", key: "country" },
        { label: "Status", key: "status" },
        { label: "Closed by", key: "closedBy" }
    ]

    useEffect(() => {
        fetchUserViewQueryList(1, 10);
    }, [selectData]);

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDelete(id)
            }
        };
        handleConfirm();
    };

    const handleDelete = async (id) => {
        const response = await deleteUserViewQuery(id);
        if (response?.code === 200) {
            fetchUserViewQueryList(1, perPage);
        }
    }

    const fetchUserViewQueryList = async (page, size) => {
        const response = await getAllUserViewQuery({ page: page, size: size, status: selectData?.statusData?.value, });
        if (response?.code === 200) {
            setRowData(response?.results?.content);
            setLoading(false);
            setTotalRows(response?.results?.totalElements);
        }
    };

    const getUserViewQueryList = async () => {
        let filterData = {
            status: selectData?.statusData?.value,
            page: 1,
            size: 100
        };
        const response = await getAllUserViewQuery(filterData);
        let csvData = []
        if (response?.code === 200) {
            let date = new Date();
            let dateMs = date.valueOf();
            const file = `page_query_list_` + epochTogmt(dateMs) + "-" + dateMs + ".csv";
            response?.results && response?.results && response?.results?.content.map((item) => {
                csvData.push({ "firstName": item?.firstName, "lastName": item?.lastName, "phoneNumber": item?.phoneNumber, "email": item.email, "companyName": item?.companyName, "website": item?.website, "city": item?.city, "state": item?.state, "country": item?.country, "createTime": epochTogmt(item?.createTime), "id": item._id, "countryCode": item?.countryISDCode ? "+" + item?.countryISDCode : "", status: item?.status, closedBy: item?.closedBy || "-" })
            })
            setExportCsvData(csvData);
            setFileName(file);
            setTimeout(() => {
                csvLink.current.link.click()
            }, 1000)
        }
    };

    const handlePageChange = page => {
        fetchUserViewQueryList(page, perPage);
    };

    const handlePerRowsChange = async (newPerPage, page) => {
        setPerPage(newPerPage);
        fetchUserViewQueryList(page, newPerPage);
    };

    const actionButton = () => {
        return (
            <React.Fragment>
                {authService.getPermission("USER_VIEW_QUERY_EXPORT_CSV") && rowData.length > 0 && <a className="btn btn-primary" href={"javascript:void(0)"} onClick={() => getUserViewQueryList()} ><i class="fa-solid fa-download" /></a>}
            </React.Fragment>
        );
    };

    const handleSelectChange = (selectedOption, selectType) => {
        setSelectData({ ...selectData, [selectType]: selectedOption });
    };

    return (<div className='row'>
        <div className="col-md-12 mb-3">
            <div className="filterSection">
                <div className="col-md-2">
                    <Select
                        options={businessStatusOption}
                        placeholder={"Filter by status"}
                        value={selectData.statusData}
                        onChange={(selectedOption) => handleSelectChange(selectedOption, 'statusData')}
                        classNamePrefix="select"
                        styles={{
                            option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                const color = '#03a68059';
                                return {
                                    ...styles,
                                    backgroundColor: isDisabled
                                        ? null
                                        : isSelected
                                            ? '#03a68059'
                                            : isFocused
                                                ? '#03a68059'
                                                : null,
                                    color: isDisabled
                                        ? '#ccc'
                                        : isSelected
                                            ? color > 2
                                                ? '#00374d'
                                                : '#00374d'
                                            : data.color,
                                    cursor: isDisabled ? 'not-allowed' : 'default',

                                    ':active': {
                                        ...styles[':active'],
                                        backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                                    },
                                };
                            },
                        }}
                    />
                </div>
            </div>
        </div>
        <div className="col2Large">
            <DataTable
                title="User View Query"
                columns={tableUserViewQueryConstant(fetchUserViewQueryList, handleConfirmModal)}
                data={rowData}
                customStyles={customStyles}
                actions={actionButton()}
                pagination
                paginationPerPage={perPage}
                pointerOnHover
                fixedHeader
                noContextMenu
                fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                progressPending={loading}
                paginationServer
                paginationTotalRows={totalRows}
                onChangeRowsPerPage={handlePerRowsChange}
                onChangePage={handlePageChange}
            />
        </div>

        <CSVLink headers={userViewQueryListHeader} data={exportCsvData} filename={fileName} ref={csvLink}></CSVLink>
    </div>)
}

export default UserViewQueryList;
